/// <summary>
/// Controller class for inventory compensation statement report
/// </summary>
public class KJP_SM_InventCompensationStmtController extends SrsReportRunController
{
}

Method.Source:
/// <summary>
///  Main method to initialize the constructor of the class
/// </summary>
/// <param name = "_args">
/// Report args
/// </param>
public static void main(Args _args)
{
    KJP_SM_InventCompensationStmtController::construct(_args).startOperation();
}

    /// <summary>
    /// Constructor method for the class
    /// </summary>
    /// <param name = "_args">
    /// Report args
    /// </param>
    /// <returns>
    /// Constructor for controller class.
    /// </returns>
    public static KJP_SM_InventCompensationStmtController construct(Args _args)
    {
        KJP_SM_InventCompensationStmtController  controller = new KJP_SM_InventCompensationStmtController();

        controller.parmReportName(ssrsReportStr(KJP_SM_InventCompensationStmtReport, Report));
        controller.parmArgs(_args);
        controller.parmLoadFromSysLastValue(false);
        controller.parmShowDialog(false);
        /*
        SRSPrintDestinationSettings settings = controller.parmReportContract().parmPrintSettings();
        settings.printMediumType(SRSPrintMediumType::File);
        settings.fileFormat(SRSReportFileFormat::PDF);
        */

        return controller;
    }

    /// <summary>
    /// Method to modify the contract before running the report.
    /// </summary>
    protected void prePromptModifyContract()
    {
        KJP_SM_InventCompensationStmtContract       contract;
        KJP_SM_InventoryCompensationHeaderTable     headerTable;
        MultiSelectionHelper                        selectionHelper = MultiSelectionHelper::construct();
        List                                        inventCompensationStmtRecIdList = new List(Types::Int64);

        selectionHelper.parmDatasource(FormDataUtil::getFormDataSource(args.record()));
        headerTable = selectionHelper.getFirst();
        
        while (headerTable.RecId != nullValueBaseType(Types::Int64))
        {
            // Capture header Recids
            inventCompensationStmtRecIdList.addEnd(headerTable.RecId);

            headerTable = selectionHelper.getNext();
        }
        
        contract = this.parmReportContract().parmRdpContract() as KJP_SM_InventCompensationStmtContract;
        contract.parmInventCompensationStmtRecIdList(inventCompensationStmtRecIdList);

        super();
    }
